const keyResp = $json;
const SUPABASE_URL = $env.SUPABASE_URL || 'https://xhpfxvoonpclonjyfimt.supabase.co';
const SUPABASE_KEY = $env.SUPABASE_SERVICE_ROLE_KEY || '';

async function fetchPipelineSecret(keyName) {
  try {
    return await this.helpers.httpRequest({
      method: 'POST',
      url: SUPABASE_URL + '/functions/v1/get-pipeline-secret',
      headers: {
        apikey: SUPABASE_KEY,
        Authorization: 'Bearer ' + SUPABASE_KEY,
        'Content-Type': 'application/json'
      },
      body: { keyName },
      json: true
    });
  } catch (e) {
    return null;
  }
}

if (keyResp && keyResp.value) {
  const key = String(keyResp.value).trim();
  if (key) {
    return [{ json: { api_key: key, source: 'db', provider: key.startsWith('hf_') ? 'huggingface' : 'groq' } }];
  }
}

for (const keyName of ['HF_API_TOKEN', 'GROQ_API_KEY']) {
  const secret = await fetchPipelineSecret.call(this, keyName);
  if (secret && secret.value) {
    const key = String(secret.value).trim();
    if (key) {
      return [{ json: { api_key: key, source: 'db:' + keyName, provider: key.startsWith('hf_') ? 'huggingface' : 'groq' } }];
    }
  }
}

const envKey = $env.HF_API_TOKEN || $env.GROQ_API_KEY || '';
if (envKey && envKey.length > 5) {
  return [{ json: { api_key: envKey, source: 'env', provider: envKey.startsWith('hf_') ? 'huggingface' : 'groq' } }];
}

throw new Error('Nenhuma chave de IA encontrada em DB ou env. Configure HF_API_TOKEN ou GROQ_API_KEY em Automações > Configurações.');

let rows;
if (Array.isArray(items[0]?.json)) {
  rows = items[0].json;
} else {
  rows = items.map(i => i.json);
}
rows = rows.filter(r => r && r.id && r.fingerprint);
if (!rows || rows.length === 0) return [];
return rows.map(c => ({ json: c }));

const cluster = $('Normalize Input').item.json;
const SUPABASE_URL = $env.SUPABASE_URL || 'https://xhpfxvoonpclonjyfimt.supabase.co';
const SUPABASE_KEY = $env.SUPABASE_SERVICE_ROLE_KEY;
let sources = $('Fetch Source Articles').all().map(i => i.json).filter(s => s && s.title);

// Load recent published posts for interlinking
let recentPosts = [];
try {
  recentPosts = $('Fetch Recent Posts (Interlink)').all().map(i => i.json).filter(p => p && p.slug);
} catch (e) { /* ok */ }

const loadRuntimeConfig = async () => {
  try {
    const resp = await this.helpers.httpRequest({
      method: 'GET',
      url: SUPABASE_URL + '/rest/v1/automations_v2?category=eq.content_pipeline&status=eq.active&order=updated_at.desc&limit=1&select=name,config,updated_at',
      headers: { 'apikey': SUPABASE_KEY, 'Content-Type': 'application/json' },
      json: true
    });
    const rows = Array.isArray(resp) ? resp : [];
    return rows[0] || null;
  } catch (e) { return null; }
};

function normalizeString(value, fallback) { const text = String(value || '').trim(); return text || (fallback || ''); }
function normalizeList(value) { if (!Array.isArray(value)) return []; const seen = new Set(); return value.map(e => String(e || '').trim()).filter(t => { if (!t) return false; const k = t.toLowerCase(); if (seen.has(k)) return false; seen.add(k); return true; }); }
function normalizeBoolean(value, fallback) { if (typeof value === 'boolean') return value; if (typeof value === 'string') { const n = value.trim().toLowerCase(); if (['true','1','yes','sim','on'].includes(n)) return true; if (['false','0','no','nao','off'].includes(n)) return false; } return fallback || false; }

if (sources.length === 0) {
  sources = [{ title: cluster.topic || 'Tecnologia', summary: 'Noticia sobre ' + (cluster.topic || 'tecnologia'), source_name: 'Vision7', canonical_url: '', topic: cluster.topic }];
}

const runtimeAutomation = await loadRuntimeConfig();
const runtimeConfig = runtimeAutomation?.config || {};
const targetTone = normalizeString(runtimeConfig.target_tone, 'vision7');
const customPrompt = normalizeString(runtimeConfig.ai_prompt);
const keywords = normalizeList(runtimeConfig.keywords);
const autoPublish = normalizeBoolean(runtimeConfig.auto_publish, false);
const reviewRequired = normalizeBoolean(runtimeConfig.review_required, true);

const sourceArticles = sources.slice(0, 5).map((source) => ({
  title: source.title || '', source_name: source.source_name || 'desconhecido',
  canonical_url: source.canonical_url || '', published_at: source.published_at || null,
  topic: source.topic || cluster.topic || null
}));

const sourceTexts = sources.slice(0, 5).map((s, i) => {
  const resumo = ((s.summary || s.content || '')).substring(0, 500);
  return 'Fonte ' + (i + 1) + ' (' + (s.source_name || 'desconhecido') + '):\nTitulo: ' + (s.title || '') + '\nResumo: ' + resumo + '\nURL: ' + (s.canonical_url || '');
}).join('\n\n');

const topicMap = { 'ia': 'Inteligencia Artificial', 'ciberseguranca': 'Ciberseguranca', 'automacao': 'Automacao', 'geral': 'Tecnologia' };
const topicLabel = topicMap[cluster.topic] || cluster.topic || 'Tecnologia';

// Build interlink suggestions
const interlinkSuggestions = recentPosts.slice(0, 5).map(p => '- [' + p.title + '](/post/' + p.slug + ')').join('\n');
const interlinkBlock = interlinkSuggestions ? '\n- Se relevante, inclui links internos para artigos relacionados do portal:\n' + interlinkSuggestions : '';

const keywordBlock = keywords.length > 0 ? '\n- Quando fizer sentido editorialmente, integra contexto relacionado com: ' + keywords.join(', ') : '';
const customPromptBlock = customPrompt ? '\n\nINSTRUCOES EDITORIAIS ADICIONAIS:\n' + customPrompt : '';

// v2: Enhanced prompt with SEO instructions
const prompt = 'Es um jornalista tecnologico portugues do portal Vision7. Escreve um artigo ORIGINAL baseado nas fontes abaixo.\n\nREGRAS:\n- Artigo 100% original, NAO copies frases das fontes\n- Tom informativo e profissional, portugues europeu\n- Entre 300 e 600 palavras\n- Inclui titulo atrativo (sem clickbait)\n- Inclui subtitulo de 1 linha\n- Inclui excerpt (resumo de 2 frases para SEO - max 160 caracteres)\n- Corpo em Markdown\n- Tema: ' + topicLabel + '\n- Tom editorial preferido: ' + targetTone + '\n- NAO inventes dados ou estatisticas\n- Cita fontes quando relevante\n\nSEO OBRIGATORIO:\n- Define UMA keyword principal para ranking\n- Define 2-3 keywords secundarias\n- A keyword principal DEVE aparecer no titulo e nos primeiros 100 caracteres\n- Inclui meta_description (max 155 caracteres)\n- Identifica a intencao de busca: informational, navigational, commercial' + keywordBlock + interlinkBlock + customPromptBlock + '\n\nFONTES:\n' + sourceTexts + '\n\nResponde APENAS em JSON valido:\n{\n  "title": "...",\n  "subtitle": "...",\n  "excerpt": "...",\n  "body_markdown": "...",\n  "topic": "' + cluster.topic + '",\n  "primary_keyword": "...",\n  "secondary_keywords": ["...", "..."],\n  "meta_description": "...",\n  "search_intent": "informational|navigational|commercial"\n}';

const finalPrompt = prompt.length > 10000 ? prompt.substring(0, 10000) + '\n\n[Fontes truncadas por limite de tamanho]' : prompt;

return [{
  json: {
    cluster_id: cluster.id,
    fingerprint: cluster.fingerprint,
    confidence_score: cluster.confidence_score,
    trend_score: cluster.trend_score || 0,
    priority_rank: cluster.priority_rank || 0,
    source_count: sources.length,
    source_articles: sourceArticles,
    topic: cluster.topic,
    prompt: finalPrompt,
    target_tone: targetTone,
    auto_publish: autoPublish,
    review_required: reviewRequired,
    keywords: keywords,
    recent_posts_for_interlink: recentPosts.map(p => ({ title: p.title, slug: p.slug })),
    automation_name: runtimeAutomation?.name || null,
    automation_updated_at: runtimeAutomation?.updated_at || null,
    custom_prompt_applied: Boolean(customPrompt)
  }
}];

const prev = $('Build AI Prompt + SEO').item.json;
const keyData = $('Validate Key').item.json;
const apiKey = keyData.api_key;
const provider = keyData.provider || (apiKey.startsWith('hf_') ? 'huggingface' : 'groq');

async function callHuggingFace(prompt, key) {
  const body = { inputs: '<s>[INST] ' + prompt + ' [/INST]', parameters: { max_new_tokens: 2000, temperature: 0.7, return_full_text: false } };
  const response = await this.helpers.httpRequest({ method: 'POST', url: 'https://api-inference.huggingface.co/models/mistralai/Mistral-7B-Instruct-v0.3', headers: { 'Authorization': 'Bearer ' + key, 'Content-Type': 'application/json' }, body: body, json: true });
  const text = Array.isArray(response) ? response[0].generated_text : response.generated_text || '';
  return { choices: [{ message: { content: text } }], provider: 'huggingface', model: 'mistralai/Mistral-7B-Instruct-v0.3' };
}

async function callGroq(prompt, key) {
  const body = { model: 'llama-3.3-70b-versatile', temperature: 0.7, max_tokens: 2000, messages: [{ role: 'system', content: 'Es um jornalista tech portugues. Responde SEMPRE em JSON valido.' }, { role: 'user', content: prompt }] };
  const response = await this.helpers.httpRequest({ method: 'POST', url: 'https://api.groq.com/openai/v1/chat/completions', headers: { 'Authorization': 'Bearer ' + key, 'Content-Type': 'application/json' }, body: body, json: true });
  return { ...response, provider: 'groq', model: 'llama-3.3-70b-versatile' };
}

try {
  const fullPrompt = 'Es um jornalista tech portugues. Responde SEMPRE em JSON valido.\n\n' + prev.prompt;
  let response;
  if (provider === 'huggingface') {
    response = await callHuggingFace.call(this, fullPrompt, apiKey);
  } else {
    response = await callGroq.call(this, prev.prompt, apiKey);
  }
  return [{ json: response }];
} catch (e) {
  if (provider === 'huggingface' && e.message && (e.message.includes('loading') || e.message.includes('503') || e.message.includes('Service Unavailable'))) {
    await new Promise(r => setTimeout(r, 30000));
    try {
      const fullPrompt = 'Es um jornalista tech portugues. Responde SEMPRE em JSON valido.\n\n' + prev.prompt;
      const response = await callHuggingFace.call(this, fullPrompt, apiKey);
      return [{ json: response }];
    } catch (e2) {
      return [{ json: { error: { message: 'HF retry failed: ' + e2.message }, choices: [], provider: 'huggingface' } }];
    }
  }
  const errDetail = e.httpCode ? ' [HTTP ' + e.httpCode + ']' : '';
  return [{ json: { error: { message: e.message + errDetail }, choices: [], provider: provider } }];
}

function mdToHtml(md) {
  if (!md) return '';
  let h = md;
  h = h.replace(/```(\w*)\n([\s\S]*?)```/g, (m, l, c) => '<pre><code>' + c.replace(/</g, '&lt;').replace(/>/g, '&gt;').trimEnd() + '</code></pre>');
  h = h.replace(/`([^`]+)`/g, '<code>$1</code>');
  h = h.replace(/!\[([^\]]*)\]\(([^)]+)\)/g, '<img src="$2" alt="$1" loading="lazy" />');
  h = h.replace(/\[([^\]]+)\]\(([^)]+)\)/g, '<a href="$2">$1</a>');
  h = h.replace(/^######\s+(.+)$/gm, '<h6>$1</h6>');
  h = h.replace(/^#####\s+(.+)$/gm, '<h5>$1</h5>');
  h = h.replace(/^####\s+(.+)$/gm, '<h4>$1</h4>');
  h = h.replace(/^###\s+(.+)$/gm, '<h3>$1</h3>');
  h = h.replace(/^##\s+(.+)$/gm, '<h2>$1</h2>');
  h = h.replace(/^#\s+(.+)$/gm, '<h1>$1</h1>');
  h = h.replace(/^[-*_]{3,}\s*$/gm, '<hr />');
  h = h.replace(/\*\*\*(.+?)\*\*\*/g, '<strong><em>$1</em></strong>');
  h = h.replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>');
  h = h.replace(/\*(.+?)\*/g, '<em>$1</em>');
  h = h.replace(/^>\s+(.+)$/gm, '<blockquote><p>$1</p></blockquote>');
  h = h.replace(/(^[\t ]*[-*]\s+.+\n?)+/gm, (block) => {
    const items = block.trim().split('\n').map(l => l.replace(/^[\t ]*[-*]\s+/, '').trim()).filter(Boolean).map(i => '<li>' + i + '</li>').join('\n');
    return '<ul>\n' + items + '\n</ul>';
  });
  h = h.replace(/(^\d+\.\s+.+\n?)+/gm, (block) => {
    const items = block.trim().split('\n').map(l => l.replace(/^\d+\.\s+/, '').trim()).filter(Boolean).map(i => '<li>' + i + '</li>').join('\n');
    return '<ol>\n' + items + '\n</ol>';
  });
  const lines = h.split('\n'); const result = []; let buf = [];
  const isBlock = l => /^<(h[1-6]|ul|ol|li|pre|blockquote|hr|img)\b/i.test(l.trim()) || /^<\/(ul|ol|pre|blockquote)>/i.test(l.trim());
  for (const line of lines) {
    if (line.trim() === '') { if (buf.length) { result.push('<p>' + buf.join(' ') + '</p>'); buf = []; } }
    else if (isBlock(line)) { if (buf.length) { result.push('<p>' + buf.join(' ') + '</p>'); buf = []; } result.push(line); }
    else { buf.push(line.trim()); }
  }
  if (buf.length) result.push('<p>' + buf.join(' ') + '</p>');
  return result.join('\n');
}
const prev = $('Build AI Prompt + SEO').item.json;
const response = $json;

if (response.error || !response.choices || response.choices.length === 0) {
  const errMsg = response.error?.message || response.error || 'No response from LLM (empty choices)';
  return [{ json: { error: 'AI generation failed: ' + errMsg, cluster_id: prev.cluster_id, provider: response.provider || 'unknown', skip: true } }];
}

function extractField(text, field) {
  const re = new RegExp('"' + field + '"\\s*:\\s*"');
  const m = re.exec(text);
  if (!m) return '';
  let start = m.index + m[0].length;
  let result = '';
  for (let i = start; i < text.length; i++) {
    if (text[i] === '\\') { result += text[i] + (text[i+1]||''); i++; continue; }
    if (text[i] === '"') { const after = text.substring(i+1).trimStart(); if (after[0] === ',' || after[0] === '}') break; result += text[i]; continue; }
    result += text[i];
  }
  return result.replace(/\n/g, ' ').replace(/\r/g, '').replace(/\t/g, ' ');
}

let article;
try {
  let content = response.choices[0].message.content;
  content = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  try { article = JSON.parse(content); } catch (e1) {
    try {
      let fixed = ''; let inStr = false; let esc = false;
      for (let i = 0; i < content.length; i++) {
        const ch = content[i];
        if (esc) { fixed += ch; esc = false; continue; }
        if (ch === '\\') { fixed += ch; esc = true; continue; }
        if (ch === '"') { inStr = !inStr; fixed += ch; continue; }
        if (inStr && ch === '\n') { fixed += '\\n'; continue; }
        if (inStr && ch === '\r') { fixed += '\\r'; continue; }
        if (inStr && ch === '\t') { fixed += '\\t'; continue; }
        fixed += ch;
      }
      article = JSON.parse(fixed);
    } catch (e2) {
      article = {
        title: extractField(content, 'title'), subtitle: extractField(content, 'subtitle'),
        excerpt: extractField(content, 'excerpt'), body_markdown: extractField(content, 'body_markdown'),
        topic: extractField(content, 'topic') || prev.topic,
        primary_keyword: extractField(content, 'primary_keyword'),
        meta_description: extractField(content, 'meta_description'),
        search_intent: extractField(content, 'search_intent') || 'informational'
      };
      if (!article.title || article.title.length < 5) throw new Error('All parse strategies failed');
    }
  }
} catch (e) {
  return [{ json: { error: 'Failed to parse AI response: ' + e.message, cluster_id: prev.cluster_id, skip: true } }];
}

// ═══ v2: Enhanced audit with SEO + readability + originality scoring ═══

const body = article.body_markdown || '';
const title = article.title || '';
const pk = article.primary_keyword || '';

// SEO Score (0-100)
let seoScore = 0;
if (pk) {
  seoScore += 20; // has primary keyword
  if (title.toLowerCase().includes(pk.toLowerCase())) seoScore += 20; // keyword in title
  if (body.substring(0, 150).toLowerCase().includes(pk.toLowerCase())) seoScore += 15; // keyword in first 150 chars
  if ((article.meta_description || '').toLowerCase().includes(pk.toLowerCase())) seoScore += 15; // keyword in meta
  const pkCount = (body.toLowerCase().match(new RegExp(pk.toLowerCase().replace(/[.*+?^${}()|[\]\\]/g, '\\$&'), 'g')) || []).length;
  if (pkCount >= 2 && pkCount <= 8) seoScore += 15; // good keyword density
  else if (pkCount >= 1) seoScore += 8;
  if (article.secondary_keywords && article.secondary_keywords.length >= 2) seoScore += 15; // has secondary keywords
}
if ((article.meta_description || '').length >= 50 && (article.meta_description || '').length <= 160) seoScore = Math.min(seoScore + 10, 100);

// Readability Score (0-100) - simple heuristic
const sentences = body.split(/[.!?]+/).filter(s => s.trim().length > 3);
const words = body.split(/\s+/).filter(w => w.length > 0);
const avgWordsPerSentence = sentences.length > 0 ? words.length / sentences.length : 0;
let readabilityScore = 70; // baseline
if (avgWordsPerSentence > 5 && avgWordsPerSentence < 25) readabilityScore += 15;
else if (avgWordsPerSentence >= 25 && avgWordsPerSentence < 35) readabilityScore += 5;
else readabilityScore -= 15;
const paragraphs = body.split(/\n\n+/).filter(p => p.trim().length > 10);
if (paragraphs.length >= 3) readabilityScore += 10;
if (body.includes('##') || body.includes('**')) readabilityScore += 5; // has formatting
readabilityScore = Math.max(0, Math.min(readabilityScore, 100));

// Originality Score (0-100) - compare against source titles
const sourceTitles = (prev.source_articles || []).map(s => (s.title || '').toLowerCase());
const titleWords = title.toLowerCase().split(/\s+/).filter(w => w.length > 3);
let commonWithSources = 0;
for (const sw of sourceTitles) {
  const sourceWords = sw.split(/\s+/).filter(w => w.length > 3);
  for (const tw of titleWords) {
    if (sourceWords.includes(tw)) commonWithSources++;
  }
}
const titleOverlap = titleWords.length > 0 ? commonWithSources / titleWords.length : 0;
let originalityScore = 100 - Math.round(titleOverlap * 60); // high overlap = low originality
originalityScore = Math.max(20, Math.min(originalityScore, 100));

// Standard audit checks
const audit = {
  has_title: Boolean(title && title.length > 10),
  has_body: Boolean(body && body.length > 200),
  has_excerpt: Boolean(article.excerpt && article.excerpt.length > 20),
  body_length: body.length,
  no_suspicious_urls: !/https?:\/\/(?!vision7|google|microsoft|apple|meta)/i.test(body),
  language_ok: /[a-zA-Z]/.test(body),
  has_primary_keyword: Boolean(pk),
  has_meta_description: Boolean(article.meta_description && article.meta_description.length >= 30),
  seo_score: seoScore,
  readability_score: readabilityScore,
  originality_score: originalityScore
};

const boolChecks = Object.entries(audit).filter(([k, v]) => typeof v === 'boolean');
const passedChecks = boolChecks.filter(([k, v]) => v === true).length;
const totalChecks = boolChecks.length;
const editorial_score = Math.round((passedChecks / totalChecks) * 100);

const autoPublish = prev.auto_publish === true;
const reviewRequired = prev.review_required === true;

// v2: Determine status with intermediary states
let status;
if (editorial_score >= 80 && seoScore >= 60 && autoPublish && !reviewRequired) {
  status = 'ready'; // ready for auto-promotion
} else if (editorial_score >= 70 && seoScore >= 40) {
  status = reviewRequired ? 'pending-review' : 'ready';
} else if (editorial_score >= 50) {
  status = 'auto-draft'; // needs human improvement
} else {
  status = 'draft'; // low quality, needs full rewrite
}

const shouldAutoPromote = status === 'ready' && autoPublish && !reviewRequired;

// Find internal link opportunities
const internalLinks = [];
const recentPostsData = prev.recent_posts_for_interlink || [];
for (const rp of recentPostsData) {
  const rpWords = (rp.title || '').toLowerCase().split(/\s+/).filter(w => w.length > 4);
  const bodyLower = body.toLowerCase();
  const matches = rpWords.filter(w => bodyLower.includes(w));
  if (matches.length >= 2) {
    internalLinks.push('/post/' + rp.slug);
  }
}

const slug = (title || 'sem-titulo').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '').replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '').substring(0, 80) + '-' + Date.now().toString(36);

return [{
  json: {
    cluster_id: prev.cluster_id,
    fingerprint: prev.fingerprint,
    title: title || 'Sem titulo',
    subtitle: article.subtitle || null,
    slug: slug,
    excerpt: article.excerpt || null,
    body_markdown: body,
    body_html: mdToHtml(body),
    language: 'pt',
    editorial_score: editorial_score,
    confidence_score: prev.confidence_score,
    seo_score: seoScore,
    readability_score: readabilityScore,
    originality_score: originalityScore,
    primary_keyword: pk || null,
    secondary_keywords: Array.isArray(article.secondary_keywords) ? article.secondary_keywords : [],
    search_intent: article.search_intent || 'informational',
    meta_description: article.meta_description || null,
    internal_links: internalLinks,
    status: status,
    tone_profile: prev.target_tone || 'vision7',
    topic: prev.topic,
    auto_publish: autoPublish,
    review_required: reviewRequired,
    should_auto_promote: shouldAutoPromote,
    keywords: Array.isArray(prev.keywords) ? prev.keywords : [],
    source_articles: Array.isArray(prev.source_articles) ? prev.source_articles : [],
    model_info: {
      provider: response?.provider || 'unknown',
      model: response?.model || 'unknown',
      source_count: prev.source_count,
      generated_at: new Date().toISOString(),
      automation_name: prev.automation_name || null,
      automation_updated_at: prev.automation_updated_at || null,
      target_tone: prev.target_tone || 'vision7',
      custom_prompt_applied: prev.custom_prompt_applied === true,
      trend_score: prev.trend_score || 0,
      priority_rank: prev.priority_rank || 0
    },
    moderation: audit,
    skip: false
  }
}];

const post = $json;
const SUPABASE_URL = $env.SUPABASE_URL || 'https://xhpfxvoonpclonjyfimt.supabase.co';
const SUPABASE_KEY = $env.SUPABASE_SERVICE_ROLE_KEY;
const headers = { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY, 'Content-Type': 'application/json', 'Prefer': 'return=representation' };
const functionHeaders = { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY, 'Content-Type': 'application/json' };

let saved = null;
try {
  saved = await this.helpers.httpRequest({
    method: 'POST',
    url: SUPABASE_URL + '/rest/v1/curated_posts',
    headers: headers,
    body: {
      cluster_id: post.cluster_id,
      title: post.title,
      subtitle: post.subtitle,
      slug: post.slug,
      excerpt: post.excerpt,
      body_markdown: post.body_markdown,
      body_html: post.body_html,
      language: post.language,
      editorial_score: post.editorial_score,
      confidence_score: post.confidence_score,
      seo_score: post.seo_score,
      readability_score: post.readability_score,
      originality_score: post.originality_score,
      primary_keyword: post.primary_keyword,
      secondary_keywords: post.secondary_keywords,
      search_intent: post.search_intent,
      meta_description: post.meta_description,
      internal_links: post.internal_links,
      status: post.status,
      tone_profile: post.tone_profile,
      model_info: post.model_info,
      moderation: post.moderation
    },
    json: true
  });
} catch (e) {
  return [{ json: { error: 'Save curated failed: ' + e.message, cluster_id: post.cluster_id } }];
}

const savedEntry = Array.isArray(saved) ? saved[0] : saved;
const wantsAutoPublish = post.auto_publish === true;
const shouldAutoPromote = post.should_auto_promote === true;
let notificationResult = null;
let notificationError = null;
let autoPromotionResult = null;
let autoPromotionError = null;

if (savedEntry?.id) {
  try {
    notificationResult = await this.helpers.httpRequest({
      method: 'POST',
      url: SUPABASE_URL + '/functions/v1/notify-curated-post',
      headers: functionHeaders,
      body: { curatedPostId: savedEntry.id, sourceArticles: Array.isArray(post.source_articles) ? post.source_articles : [] },
      json: true
    });
  } catch (e) { notificationError = e.message; }
}

if (savedEntry?.id && shouldAutoPromote) {
  try {
    autoPromotionResult = await this.helpers.httpRequest({
      method: 'POST',
      url: SUPABASE_URL + '/functions/v1/promote-curated-post',
      headers: functionHeaders,
      body: { curatedPostId: savedEntry.id },
      json: true
    });
  } catch (e) { autoPromotionError = e.message; }
}

// Mark cluster as curated to prevent WF-03 from re-processing the same cluster
if (savedEntry?.id && post.cluster_id) {
  try {
    await this.helpers.httpRequest({
      method: 'PATCH',
      url: SUPABASE_URL + '/rest/v1/news_clusters?id=eq.' + post.cluster_id,
      headers: { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY, 'Content-Type': 'application/json' },
      body: { is_curated: true, curated_at: new Date().toISOString() },
      json: true
    });
  } catch (e) { /* non-fatal: cluster marked on next run */ }
}

const autoPromotionSucceeded = !autoPromotionError && ['promoted', 'duplicate', 'already_published'].includes(String(autoPromotionResult?.status || ''));
const finalStatus = autoPromotionSucceeded ? 'published' : (savedEntry?.status || post.status || 'draft');
const readyForReview = ['pending-review', 'auto-draft', 'ready'].includes(finalStatus) || (shouldAutoPromote && !autoPromotionSucceeded);

return [{
  json: {
    success: true,
    draft_auto: autoPromotionResult?.promoted === true,
    auto_publish_requested: wantsAutoPublish,
    auto_promotion_attempted: shouldAutoPromote,
    auto_promotion_status: autoPromotionResult?.status || null,
    auto_promotion_error: autoPromotionError,
    curation_notification_status: notificationResult?.status || null,
    curation_notification_error: notificationError,
    ready_for_review: readyForReview,
    curated_post_id: savedEntry?.id || null,
    post_id: autoPromotionResult?.postId || null,
    slug: autoPromotionResult?.slug || savedEntry?.slug || post.slug || null,
    title: post.title,
    editorial_score: post.editorial_score,
    seo_score: post.seo_score,
    readability_score: post.readability_score,
    originality_score: post.originality_score,
    primary_keyword: post.primary_keyword,
    status: finalStatus
  }
}];

